import{_ as a,o,c as r,a3 as n}from"./chunks/framework.CjquFG0V.js";const w=JSON.parse('{"title":"30A. Lead Apron Allowance","description":"","frontmatter":{"title":"30A. Lead Apron Allowance","eba":"Nurses and Midwives 2024-2028","topics":["hours","shift-work","breaks","allowances"]},"headers":[],"relativePath":"ebas/nurses-midwives/allowances/30A-lead-apron-allowance.md","filePath":"ebas/nurses-midwives/allowances/30A-lead-apron-allowance.md"}'),t={name:"ebas/nurses-midwives/allowances/30A-lead-apron-allowance.md"};function s(l,e,i,d,p,c){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="_30a-lead-apron-allowance" tabindex="-1">30A. Lead Apron Allowance <a class="header-anchor" href="#_30a-lead-apron-allowance" aria-label="Permalink to &quot;30A. Lead Apron Allowance&quot;">​</a></h1><p><strong>30A.1</strong> An Employee who is required as part of their usual duties to wear a lead apron, is to be paid the Lead Apron Allowance in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a> for each shift or part thereof on which the lead apron is worn.</p><p><strong>30A.2</strong> Additional Break</p><p>In addition to the breaks prescribed at <a href="/eba/ebas/nurses-midwives/hours-of-work/44-breaks.html">clause 44</a> (Breaks), Employees who are required to wear lead for greater than three hours continuously will be entitled to a 10-minute paid break. The break is to be taken as soon as practicable after it is due and without the expectation of wearing the apron during the break. Such breaks may be taken in conjunction with meal or other breaks provided under this Agreement.</p>',4)])])}const u=a(t,[["render",s]]);export{w as __pageData,u as default};
